use std::thread;
use std::time::Duration;
use winapi::ctypes::{c_int, wchar_t};
use winapi::shared::minwindef::LPARAM;
use winapi::shared::windef::HWND;
use winapi::um::shellapi::{AddClipboardFormatListener, RemoveClipboardFormatListener, SendMessageW};
use winapi::um::winuser::{
    CF_TEXT, GetClipboardFormatNameW, GetClipboardOwner, GetClipboardData, GetClipboardSequenceNumber,
    OpenClipboard, CloseClipboard, SetClipboardViewer,
};
use lazy_static::lazy_static;
use std::ffi::OsStr;
use std::os::windows::ffi::OsStrExt;
use std::ptr::null_mut;

lazy_static! {
    static ref CF_TEXT_W: Vec<u16> = OsStr::new("CF_TEXT")
        .encode_wide()
        .chain(std::iter::once(0))
        .collect();
}

unsafe extern "system" fn clipboard_viewer_callback(hwnd: HWND, msg: u32, wparam: LPARAM, lparam: LPARAM) -> c_int {
    if msg == winapi::um::winuser::WM_DRAWCLIPBOARD {
        let mut clipboard = Clipboard::new().unwrap();
        if clipboard.get_contents().is_ok() {
            println!("{}", clipboard.get_contents().unwrap());
        }
    }
    SendMessageW(winapi::um::winuser::GetClipboardOwner(), msg, wparam, lparam) as c_int
}

fn main() {
    unsafe {
        if OpenClipboard(null_mut()) == 0 {
            println!("Failed to open clipboard");
            return;
        }

        let previous_viewer = SetClipboardViewer(0 as HWND);
        AddClipboardFormatListener(winapi::um::shellapi::Shell_GetConsoleWindow() as HWND);

        loop {
            let msg = GetMessageW(null_mut(), 0 as HWND, 0, 0);
            if msg == -1 {
                break;
            }
            TranslateMessage(msg);
            DispatchMessageW(msg);
        }

        RemoveClipboardFormatListener(winapi::um::shellapi::Shell_GetConsoleWindow() as HWND);
        CloseClipboard();
        ChangeClipboardChain(previous_viewer, winapi::um::winuser::GetClipboardOwner());
    }
}

