To make an HTTP request in JavaScript, you can use the built-in `XMLHttpRequest` object or the `fetch` API, which is a more modern and simpler way to make requests. Here's an example using both methods:

**Method 1: Using XMLHttpRequest**

```javascript
function makeHttpGetRequest(url, callback) {
 const xhr = new XMLHttpRequest();
  xhr.open('GET', url, true);

  xhr.onload = function() {
    if (xhr.status >= 200 && xhr.status < 400) {
      callback(xhr.responseText);
    } else {
      console.error(`Error: ${xhr.status} - ${xhr.statusText}`);
    }
  };

  xhr.onerror = function() {
    console.error('An error occurred during the request.');
  };

  xhr.send();
}

// Usage
makeHttpGetRequest('https://api.example.com/data', (response) => {
 console.log(response);
});
```

**Method 2: Using fetch API**

```javascript
function makeHttpGetRequest(url) {
  return fetch(url)
    .then((response) => {
      if (response.ok) {
        return response.text();
      } else {
        throw new Error(`Error: ${response.status} - ${response.statusText}`);
      }
    })
    .then((data) => {
      console.log(data);
    })
    .catch((error) => {
      console.error(error);
    });
}

// Usage
