@app.route('/counter/decrement', methods=['POST'])
def decrement_counter():
    data = request.get_json()
    if 'amount' in data:
        amount = data['amount']
        counter = Counter.query.first()
        if counter.value >= amount:
            counter.value -= amount
            db.session.commit()
            return jsonify(new_value=counter.value)
        else:
            return jsonify(error="Insufficient counter value"), 400
