// Import required libraries
import { jsPsych } from './jspsych-6.1.0/jspsych';
import { jsPsychHtmlKeyboardResponse } from './jspsych-6.1.0/plugins/jspsych-html-keyboard-response';
import { jsPsychImageKeyboardResponse } from './jspsych-6.1.0/plugins/jspsych-image-keyboard-response';

// Set up experiment parameters
